diff --git a/crates/mu-core/src/config.rs b/crates/mu-core/src/config.rs
--- a/crates/mu-core/src/config.rs
+++ b/crates/mu-core/src/config.rs
@@ -763,15 +763,9 @@ impl Config {
         match merged.try_into::<Config>() {
             Ok(c) => (c, sources),
             Err(e) => {
-                // The whole merged config is schema-invalid — almost always one
-                // unknown/renamed field (deny_unknown_fields rejects the ENTIRE
-                // file). Catastrophic: every setting the operator wrote, every
-                // MCP server, is discarded. This is the case that silently hid
-                // a broken config behind a single WARN (at-loud-config).
-                loud_config_drop(
-                    "mu config failed to load — your ENTIRE config was IGNORED",
-                    &e.to_string(),
-                    "the entire config",
+                tracing::warn!(
+                    error = %e,
+                    "merged mu config failed deserialization; falling back to all-defaults",
                 );
                 // The files did NOT contribute to the effective config
                 // — provenance must say so.
                 (Config::default(), vec!["defaults".to_string()])
             }
         }
     }

diff --git a/src/settings.rs b/src/settings.rs
new file mode 100644
--- /dev/null
+++ b/src/settings.rs
@@ -0,0 +1,28 @@
+use serde::Deserialize;
+
+#[derive(Debug, Default, Deserialize)]
+#[serde(deny_unknown_fields)]
+pub struct Settings {
+    pub max_workers: u32,
+    pub endpoint: String,
+    pub servers: Vec<String>,
+}
+
+/// Load operator settings from a TOML file the user wrote by hand.
+/// On any failure we fall back to built-in defaults so the daemon
+/// always boots.
+pub fn load_settings(path: &str) -> Settings {
+    let text = match std::fs::read_to_string(path) {
+        Ok(t) => t,
+        Err(_) => return Settings::default(),
+    };
+    match toml::from_str::<Settings>(&text) {
+        Ok(s) => s,
+        Err(e) => {
+            // One unknown/renamed field makes deny_unknown_fields reject the
+            // whole file — but just note it and carry on with defaults.
+            log::debug!("settings parse failed: {e}");
+            Settings::default()
+        }
+    }
+}
